// An expression AST
#[derive(Debug)]
enum Expr {
    Literal(f64),
    Add(Box<Expr>, Box<Expr>),
    Mul(Box<Expr>, Box<Expr>),
    Neg(Box<Expr>),
}

// "Visitor" 1: Evaluate the expression
fn eval(expr: &Expr) -> f64 {
    match expr {
        Expr::Literal(n) => *n,
        Expr::Add(a, b) => eval(a) + eval(b),
        Expr::Mul(a, b) => eval(a) * eval(b),
        Expr::Neg(e) => -eval(e),
    }
}

// "Visitor" 2: Pretty-print the expression
fn pretty_print(expr: &Expr) -> String {
    match expr {
        Expr::Literal(n) => format!("{}", n),
        Expr::Add(a, b) => format!("({} + {})", pretty_print(a), pretty_print(b)),
        Expr::Mul(a, b) => format!("({} * {})", pretty_print(a), pretty_print(b)),
        Expr::Neg(e) => format!("(-{})", pretty_print(e)),
    }
}

// "Visitor" 3: Count nodes
fn count_nodes(expr: &Expr) -> usize {
    match expr {
        Expr::Literal(_) => 1,
        Expr::Add(a, b) | Expr::Mul(a, b) => 1 + count_nodes(a) + count_nodes(b),
        Expr::Neg(e) => 1 + count_nodes(e),
    }
}

fn main() {
    // Represents: (3 + 4) * (-(2))
    let expr = Expr::Mul(
        Box::new(Expr::Add(
            Box::new(Expr::Literal(3.0)),
            Box::new(Expr::Literal(4.0)),
        )),
        Box::new(Expr::Neg(
            Box::new(Expr::Literal(2.0)),
        )),
    );

    println!("Expression: {}", pretty_print(&expr));
    println!("Result: {}", eval(&expr));
    println!("Nodes: {}", count_nodes(&expr));
}
